import React from 'react';
import SFX from '../utils/sfx';
import HackathonCard from './HackathonCard';
import CertificatesCard from './CertificatesCard';
import './Home.css';
import './Components.css';

const Home = () => {
  const [activeSlice, setActiveSlice] = React.useState(null);
  return (
    <div className="home-container">
      {/* Subtle PS2-style pillar ambient layer */}
      <div className="ps2-pillar-field" aria-hidden="true">
        <span className="pillar p1" />
        <span className="pillar p2" />
        <span className="pillar p3" />
        <span className="pillar p4" />
        <span className="pillar p5" />
        <span className="pillar p6" />
      </div>
      <div className="scanline-layer">
        <div className="scanline blue slow"></div>
        <div className="scanline cyan fast"></div>
        <div className="scanline cyan medium"></div>
      </div>
      <header>
        <h1 data-text="Andy Mackay">Andy Mackay</h1>
        <p>Game Developer Portfolio</p>
      </header>

      <div className="content-wrapper">
        {/* About Me Section */}
        <section className="about-me">
        <h2>About Me</h2>
        <div className="about-card">
          <p>I'm a passionate game developer with a strong foundation in both Unity and Unreal Engine. My journey in game development started with modding existing games, which evolved into creating my own unique gaming experiences.</p>
          <p>With expertise in C#, C++, and game design principles, I focus on crafting engaging gameplay mechanics and optimizing performance. I thrive in collaborative environments and enjoy tackling complex technical challenges.</p>
          <div className="tech-stack">
            <span>Unity</span>
            <span>Unreal Engine</span>
            <span>C#</span>
            <span>C++</span>
            <span>Game Design</span>
          </div>
        </div>
      </section>

  {/* Showcase Section (moved above Featured Game) */}
      <section className="showcase">
        <h2>Vertical Slices</h2>
        <div className={`slices-grid ${activeSlice ? 'slice-activating' : ''}`}>
          <div className={`slice ${activeSlice === 's1' ? 'activating' : ''}`}>
            <div className="video-preview">
              <div className="video-thumbnail">
                <img src={`${process.env.PUBLIC_URL}/images/project1-thumb.jpg`} alt="Project One Thumbnail" />
                <button 
                  className="play-overlay" 
                  onMouseOver={() => SFX.play('hover')}
                  onClick={() => {
                    SFX.play('open');
                    setActiveSlice('s1');
                    document.body.style.overflow = 'hidden';
                    setTimeout(() => document.getElementById('video-modal-1').classList.add('show'), 220);
                  }}
                >
                  <span className="play-icon">▶</span>
                </button>
              </div>
              <div id="video-modal-1" className="video-modal">
                <div className="modal-content" id="vmc-1">
                  <div className="loading-overlay">
                    <div className="loading-spinner"></div>
                    <p>Loading Video...</p>
                  </div>
                  <video controls onCanPlayThrough={() => document.getElementById('vmc-1')?.classList.add('video-ready')}>
                    <source src={`${process.env.PUBLIC_URL}/videos/project1.mp4`} type="video/mp4" />
                  </video>
                  <button 
                    className="close-btn"
                    onMouseOver={() => SFX.play('hover')}
                    onClick={() => {
                      SFX.play('close');
                      const modal = document.getElementById('video-modal-1');
                      const video = modal.querySelector('video');
                      video.pause();
                      video.currentTime = 0;
                      modal.classList.remove('show');
                      document.body.style.overflow = '';
                      setActiveSlice(null);
                    }}
                  >✕</button>
                </div>
              </div>
            </div>
            <div className="slice-content">
              <h3>Project One</h3>
              <p className="slice-description">A brief overview of the first vertical slice...</p>
              <details className="slice-details">
                <summary>Read More</summary>
                <p>Detailed description of the project, including technical specifications, challenges overcome, and key features implemented.</p>
              </details>
            </div>
          </div>

          <div className={`slice ${activeSlice === 's2' ? 'activating' : ''}`}>
            <div className="video-preview">
              <div className="video-thumbnail">
                <img src={`${process.env.PUBLIC_URL}/images/project2-thumb.jpg`} alt="Project Two Thumbnail" />
                <button 
                  className="play-overlay" 
                  onMouseOver={() => SFX.play('hover')}
                  onClick={() => {
                    SFX.play('open');
                    setActiveSlice('s2');
                    document.body.style.overflow = 'hidden';
                    setTimeout(() => document.getElementById('video-modal-2').classList.add('show'), 220);
                  }}
                >
                  <span className="play-icon">▶</span>
                </button>
              </div>
              <div id="video-modal-2" className="video-modal">
                <div className="modal-content" id="vmc-2">
                  <div className="loading-overlay">
                    <div className="loading-spinner"></div>
                    <p>Loading Video...</p>
                  </div>
                  <video controls onCanPlayThrough={() => document.getElementById('vmc-2')?.classList.add('video-ready')}>
                    <source src={`${process.env.PUBLIC_URL}/videos/project2.mp4`} type="video/mp4" />
                  </video>
                  <button 
                    className="close-btn"
                    onMouseOver={() => SFX.play('hover')}
                    onClick={() => {
                      SFX.play('close');
                      const modal = document.getElementById('video-modal-2');
                      const video = modal.querySelector('video');
                      video.pause();
                      video.currentTime = 0;
                      modal.classList.remove('show');
                      document.body.style.overflow = '';
                      setActiveSlice(null);
                    }}
                  >✕</button>
                </div>
              </div>
            </div>
            <div className="slice-content">
              <h3>Project Two</h3>
              <p className="slice-description">A brief overview of the second vertical slice...</p>
              <details className="slice-details">
                <summary>Read More</summary>
                <p>Detailed description of the project, including technical specifications, challenges overcome, and key features implemented.</p>
              </details>
            </div>
          </div>

          <div className={`slice ${activeSlice === 's3' ? 'activating' : ''}`}>
            <div className="video-preview">
              <div className="video-thumbnail">
                <img src={`${process.env.PUBLIC_URL}/images/project3-thumb.jpg`} alt="Project Three Thumbnail" />
                <button 
                  className="play-overlay" 
                  onMouseOver={() => SFX.play('hover')}
                  onClick={() => {
                    SFX.play('open');
                    setActiveSlice('s3');
                    document.body.style.overflow = 'hidden';
                    setTimeout(() => document.getElementById('video-modal-3').classList.add('show'), 220);
                  }}
                >
                  <span className="play-icon">▶</span>
                </button>
              </div>
              <div id="video-modal-3" className="video-modal">
                <div className="modal-content" id="vmc-3">
                  <div className="loading-overlay">
                    <div className="loading-spinner"></div>
                    <p>Loading Video...</p>
                  </div>
                  <video controls onCanPlayThrough={() => document.getElementById('vmc-3')?.classList.add('video-ready')}>
                    <source src={`${process.env.PUBLIC_URL}/videos/project3.mp4`} type="video/mp4" />
                  </video>
                  <button 
                    className="close-btn"
                    onMouseOver={() => SFX.play('hover')}
                    onClick={() => {
                      SFX.play('close');
                      const modal = document.getElementById('video-modal-3');
                      const video = modal.querySelector('video');
                      video.pause();
                      video.currentTime = 0;
                      modal.classList.remove('show');
                      document.body.style.overflow = '';
                      setActiveSlice(null);
                    }}
                  >✕</button>
                </div>
              </div>
            </div>
            <div className="slice-content">
              <h3>Project Three</h3>
              <p className="slice-description">A brief overview of the third vertical slice...</p>
              <details className="slice-details">
                <summary>Read More</summary>
                <p>Detailed description of the project, including technical specifications, challenges overcome, and key features implemented.</p>
              </details>
            </div>
          </div>
        </div>
      </section>

      {/* Featured Game Section (moved below Vertical Slices) */}
  <section className="featured-game">
        <h2>Featured Game</h2>
        <div className="game-card">
          <div className="corner-glow cg1" />
            <div className="corner-glow cg2" />
            <div className="game-info">
              <h3>Game Title</h3>
              <p>A brief description of your featured game. Explain the core mechanics and what makes it unique.</p>
            </div>
            <div className="game-preview">
              <div className="preview-container">
                <div className="thumbnail-view">
                  <img
                    src={`${process.env.PUBLIC_URL}/images/game-thumbnail.jpg`}
                    alt="Game Preview"
                    className="game-thumbnail"
                  />
                  <button className="play-preview-btn" onMouseOver={() => SFX.play('hover')} onClick={() => {
                    SFX.play('click');
                    const container = document.querySelector('.preview-container');
                    if (container) container.classList.add('show-game');
                  }}>
                    <span className="play-icon">▶</span>
                    Play Game
                  </button>
                </div>
                <div className="game-view">
                  <div className="loading-overlay">
                    <div className="loading-spinner"></div>
                    <p>Loading Game...</p>
                  </div>
                  <iframe
                    src={`${process.env.PUBLIC_URL}/webgl-builds/game/index.html`}
                    title="Featured Unity WebGL Game"
                    allow="autoplay; fullscreen"
                    className="game-frame"
                  ></iframe>
                  <button className="close-btn" onMouseOver={() => SFX.play('hover')} onClick={() => {
                    SFX.play('close');
                    const container = document.querySelector('.preview-container');
                    if (container) container.classList.remove('show-game');
                  }}>✕</button>
                </div>
              </div>
            </div>
            <div className="game-footer">
              <div className="game-controls">
                <div className="control-info">
                  <p>Controls:</p>
                  <span>WASD - Move</span>
                  <span>Space - Jump</span>
                  <span>Mouse - Look</span>
                </div>
              </div>
              <a href={`${process.env.PUBLIC_URL}/downloads/game.zip`} className="download-btn" download onMouseOver={() => SFX.play('hover')} onClick={() => SFX.play('click')}>
                <span className="download-icon">↓</span>
                Download Game
              </a>
            </div>
        </div>
      </section>

      {/* Work Experience Section */}
      <section className="work-experience">
        <h2>Work Experience</h2>
        <div className="experience-card">
          <div className="experience-entry">
            <h3>Software Engineering Intern – Company A</h3>
            <p>Worked on Unity mobile development, fixing UI bugs and implementing gameplay features with C# and TextMesh Pro.</p>
          </div>
          <div className="experience-entry">
            <h3>Web Developer – Company B</h3>
            <p>Developed an ASP.NET Core + Angular shopping app with CRUD functionality and REST API integration.</p>
          </div>
          <div className="experience-entry">
            <h3>Gameplay Programmer – Project X</h3>
            <p>Built a 2.5D platformer prototype with waypoint-based moving platforms, collision detection, and animated UI menus.</p>
          </div>
        </div>
      </section>

      {/* Hackathon / Game Jam Card */}
      <section className="hackathon-section" style={{padding: '0 20px', margin: '0 0 3.5rem'}}>
        <HackathonCard />
      </section>

      {/* Certificates Section */}
      <section className="certificates-section" style={{padding: '0 20px', margin: '0 0 4rem'}}>
        <CertificatesCard />
      </section>
      </div>
    </div>
  );
};

export default Home;
